/**
 * Project gallery data. Drives the filterable Gallery page, the before/after
 * sliders, the homepage "featured work" strip, and ImageObject JSON-LD.
 *
 * Images are tasteful SVG placeholders generated by
 * `scripts/generate-placeholders.mjs` with keyword-rich filenames. Replace the
 * files in /public/images/gallery with real project photos (.jpg/.webp) when
 * the client supplies them — keep the descriptive filenames for image SEO.
 */

export type GalleryCategory = {
  slug: string;
  label: string;
};

export const galleryCategories: GalleryCategory[] = [
  { slug: "all", label: "All Projects" },
  { slug: "tree-removal", label: "Tree Removal" },
  { slug: "stump-grinding", label: "Stump Grinding" },
  { slug: "mulching", label: "Mulching" },
  { slug: "landscape-design", label: "Landscape Design" },
  { slug: "cleanup", label: "Cleanups" },
];

export type GalleryImage = {
  src: string;
  /** Keyword-rich, descriptive alt text (image SEO + accessibility). */
  alt: string;
  width: number;
  height: number;
};

export type GalleryItem = {
  id: string;
  title: string;
  category: Exclude<GalleryCategory["slug"], "all">;
  location: string;
  description: string;
  /** A before/after pair renders a comparison slider; otherwise a single image. */
  before?: GalleryImage;
  after: GalleryImage;
  featured?: boolean;
};

