export function getFeaturedItems(): GalleryItem[] {
  return galleryItems.filter((i) => i.featured);
}

export function itemsByCategory(category: string): GalleryItem[] {
  if (category === "all") return galleryItems;
  return galleryItems.filter((i) => i.category === category);
}
